/* PUBLISH: register a locally-held pattern set into the federation
 * registry.  The caller supplies the canonical 32-byte mhash (the
 * sealed identity) and the tier in the federation hierarchy.  Returns
 * a handle (slot+1) or 0 on failure.
 *
 * ANCESTRY INVARIANT (W4.2 complete): the (tier, mhash) pair MUST trace
 * to a FOUNDERS-ANCHOR-descended fed_seal anchor before a slot is
 * allocated.  Callers must call fed_seal_anchor(tier, mhash_ptr, ...)
 * before calling pattern_set_fed_publish.  Unvouched sets return 0 and
 * no slot is consumed -- the same gate pattern_set_fed_fetch enforces
 * at L222.  This closes the publish/fetch asymmetry so the registry
 * invariant (all live slots are anchored) holds for BOTH admission paths. */
fn pattern_set_fed_publish(local_set_id: u64, tier: u32, mhash_ptr: u64) -> u64 @export {
    if mhash_ptr == 0u64 { return 0u64 }
    /* ANCESTRY GATE: refuse any (tier, mhash) that has no fed_seal anchor. */
    let l_tier : u32 = tier
    let l_mhash : u64 = mhash_ptr
    let anchor_slot : u32 = fed_seal_lookup_anchor(l_tier, l_mhash)
    if anchor_slot == 0xFFFFFFFFu32 { return 0u64 }
    let s : u32 = _psf_alloc_slot()
    if s == PSF_NOT_FOUND { return 0u64 }
    _psf_copy_mhash_in(s, l_mhash)
    PSF_TIER[s]     = l_tier
    PSF_LOCAL_ID[s] = local_set_id
    PSF_LIVE[s]     = 1u8
    if PSF_USED < PSF_SLOTS { PSF_USED = PSF_USED + 1u32 }
    return (s as u64) + 1u64
}

/* 946 -- W4.2 COMPLETE: pattern_set_fed_publish now enforces the FOUNDERS-ANCHOR ancestry gate
 * (fed_seal_lookup_anchor) identically to pattern_set_fed_fetch.  The registry invariant -- every
 * live slot is anchored -- holds for BOTH admission paths.
 *
 * Negative arm: an unvouched publish (no fed_seal anchor) returns 0 and allocates no slot.
 * Positive arm: after pre-anchoring via fed_seal_anchor, publish succeeds and
 *               pattern_set_fed_verify_ancestry confirms the slot is anchored.
 * Exit 99 = pass. */
module corpus_946

extern @abi(c-msvc-x64) fn fed_seal_clear() -> i32 from "fed_seal.iii"
extern @abi(c-msvc-x64) fn fed_seal_anchor(child_tier: u32, child_root_ptr: u64, parent_tier: u32, parent_root_ptr: u64) -> i32 from "fed_seal.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_reset() -> i32 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_publish(local_set_id: u64, tier: u32, mhash_ptr: u64) -> u64 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_count() -> u32 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_verify_ancestry(handle: u64) -> u8 from "pattern_set_federation.iii"

var PSF_M  : [u8; 32]
var PSF_PR : [u8; 32]

fn main() -> u64 {
    fed_seal_clear()
    pattern_set_fed_reset()
    if pattern_set_fed_count() != 0u32 { return 1u64 }

    /* Populate PSF_M (child mhash) and PSF_PR (parent root). */
    let mut i : u32 = 0u32
    while i < 32u32 { PSF_M[i] = (i + 1u32) as u8  i = i + 1u32 }
    let mut j : u32 = 0u32
    while j < 32u32 { PSF_PR[j] = (j + 0x40u32) as u8  j = j + 1u32 }

    /* NEGATIVE: publish an unvouched (tier=1, mhash=PSF_M) set -- no anchor exists yet.
     * The ancestry gate must REJECT it: return 0, allocate no slot. */
    let h_bad : u64 = pattern_set_fed_publish(0u64, 1u32, (&PSF_M) as u64)
    if h_bad != 0u64 { return 2u64 }
    if pattern_set_fed_count() != 0u32 { return 3u64 }

    /* Bogus handles still rejected. */
    if pattern_set_fed_verify_ancestry(0u64)    != 0u8 { return 4u64 }
    if pattern_set_fed_verify_ancestry(9999u64) != 0u8 { return 5u64 }

    /* POSITIVE: pre-anchor (tier=1, PSF_M) -> (tier=2, PSF_PR) in fed_seal, then publish.
     * fed_seal_anchor requires parent_tier > child_tier (tier 2 > tier 1: valid). */
    if fed_seal_anchor(1u32, (&PSF_M) as u64, 2u32, (&PSF_PR) as u64) != 0i32 { return 6u64 }

    /* Now publish must succeed: the anchor exists. */
    let h : u64 = pattern_set_fed_publish(0u64, 1u32, (&PSF_M) as u64)
    if h == 0u64 { return 7u64 }
    if pattern_set_fed_count() != 1u32 { return 8u64 }

    /* verify_ancestry on the live handle must confirm the anchor. */
    if pattern_set_fed_verify_ancestry(h) != 1u8 { return 9u64 }

    return 99u64
}

/* C:\Users\Edwin Boston\OneDrive\Desktop\III\STDLIB\corpus\247_first_domain_pattern_set.iii
 *
 * III conformance corpus 247 -- first domain pattern set demonstration.
 *
 * This corpus demonstrates the end-to-end III-AI federation lifecycle
 * by simulating a domain expert publishing a sealed "numera" pattern
 * set and a peer node discovering + verifying it.
 *
 * Steps (all within one process for v1.0; real multi-node deployment
 * routes the FETCH step over a sealed_channel):
 *
 *   0. PRE-ANCHOR: establish fed_seal anchor for (tier=1, C247_MHASH) before
 *      calling pattern_set_fed_publish.  The registry ancestry invariant requires
 *      every live slot to be anchored; publish now enforces this at admission.
 *
 *   1. PUBLISHER side:
 *      a. Compute the sealed mhash of the numera domain (SHA-256 over
 *         the canonical interface bytes representing the domain).
 *      b. Anchor (tier=1, mhash) -> (tier=2, C247_PARENT) via fed_seal_anchor.
 *      c. Call pattern_set_fed_publish with (local_set_id=0 for now,
 *         tier=1 (NUMERA tier), mhash).
 *      d. Verify the published handle is non-zero and that
 *         pattern_set_fed_count() incremented.
 *
 *   2. DISCOVERY side:
 *      a. Iterate via pattern_set_fed_at(idx); confirm the published
 *         entry surfaces.
 *      b. Read back the mhash via pattern_set_fed_mhash_byte; verify
 *         byte-equality with what was published.
 *      c. Verify tier accessor returns 1.
 *      d. Verify pattern_set_fed_verify_ancestry confirms the slot is anchored.
 *
 *   3. RESET: pattern_set_fed_reset() clears the registry; subsequent
 *      count is 0 and discovery returns no handles.
 *
 * Mandate 7: every operation is structural.  No usage frequency, no
 * timing, no learning.  Same input bytes -> same mhash; same mhash ->
 * same registry behavior.
 *
 * Exit code: 99 on full pass; 1..N on specific failure.
 */

module corpus_247

extern @abi(c-msvc-x64) fn fed_seal_clear() -> i32 from "fed_seal.iii"
extern @abi(c-msvc-x64) fn fed_seal_anchor(child_tier: u32, child_root_ptr: u64, parent_tier: u32, parent_root_ptr: u64) -> i32 from "fed_seal.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_publish(local_set_id: u64, tier: u32, mhash_ptr: u64) -> u64 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_count() -> u32 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_at(idx: u32) -> u64 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_mhash_byte(handle: u64, idx: u32) -> u32 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_tier(handle: u64) -> u32 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_reset() -> i32 from "pattern_set_federation.iii"
extern @abi(c-msvc-x64) fn pattern_set_fed_verify_ancestry(handle: u64) -> u8 from "pattern_set_federation.iii"

extern @abi(c-msvc-x64) fn sha256_oneshot(in_ptr: *u8, in_len: u64, out_32: *u8) -> u32 from "sha256.iii"

/* Canonical interface bytes for the "numera" domain.  In production this
 * would be the serialized pattern signature: function names + arities +
 * sealed K values.  For this corpus, a deterministic placeholder string
 * suffices to exercise the federation pipeline. */
var C247_INTERFACE : [u8; 32]
var C247_MHASH     : [u8; 32]
var C247_PARENT    : [u8; 32]   /* fixed parent-tier root for the fed_seal anchor */

fn main() -> u64 {
    fed_seal_clear()
    pattern_set_fed_reset()
    if pattern_set_fed_count() != 0u32 { return 1u64 }

    /* Step 1a: compute domain mhash. */
    let mut i : u64 = 0u64
    while i < 32u64 {
        C247_INTERFACE[i] = ((i * 7u64 + 13u64) & 0xFFu64) as u8
        i = i + 1u64
    }
    sha256_oneshot((&C247_INTERFACE) as *u8, 32u64, (&C247_MHASH) as *u8)

    /* Step 1b (pre-anchor): fill a deterministic parent root and anchor
     * (tier=1, C247_MHASH) -> (tier=2, C247_PARENT) so publish can gate on it. */
    let mut p : u64 = 0u64
    while p < 32u64 {
        C247_PARENT[p] = ((p * 3u64 + 0x80u64) & 0xFFu64) as u8
        p = p + 1u64
    }
    if fed_seal_anchor(1u32, (&C247_MHASH) as u64, 2u32, (&C247_PARENT) as u64) != 0i32 { return 2u64 }

    /* Step 1c: publish the anchored domain at tier 1. */
    let h : u64 = pattern_set_fed_publish(0u64, 1u32, (&C247_MHASH) as u64)
    if h == 0u64 { return 3u64 }
    if pattern_set_fed_count() != 1u32 { return 4u64 }

    /* Step 2a: discovery returns the published handle. */
    let disc : u64 = pattern_set_fed_at(0u32)
    if disc != h { return 5u64 }

    /* Step 2b: mhash bytes match. */
    let mut k : u32 = 0u32
    while k < 32u32 {
        let stored : u32 = pattern_set_fed_mhash_byte(disc, k)
        let expected : u32 = (C247_MHASH[(k as u64) & 0xFFu64] as u32) & 0xFFu32
        if stored != expected { return 6u64 }
        k = k + 1u32
    }

    /* Step 2c: tier accessor. */
    if pattern_set_fed_tier(disc) != 1u32 { return 7u64 }

    /* Step 2d: verify_ancestry confirms the live slot is anchored. */
    if pattern_set_fed_verify_ancestry(disc) != 1u8 { return 8u64 }

    /* Determinism: publishing the same anchored mhash again at the same tier
     * returns a NEW handle (federation is bag-like, not set-like, since
     * tier may differ across versions).  Total count = 2. */
    let h2 : u64 = pattern_set_fed_publish(0u64, 1u32, (&C247_MHASH) as u64)
    if h2 == 0u64 { return 9u64 }
    if h2 == h { return 10u64 }
    if pattern_set_fed_count() != 2u32 { return 11u64 }

    /* Step 3: reset clears all. */
    pattern_set_fed_reset()
    if pattern_set_fed_count() != 0u32 { return 12u64 }
    if pattern_set_fed_at(0u32) != 0u64 { return 13u64 }

    return 99u64
}
